CREATE OR REPLACE FUNCTION fpa_get_resign_cause_name (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_cause_name  sc_mem_m_ucf_resign_cause.resign_cause_name%type;

BEGIN
select	resign_cause_name into STRICT ls_cause_name
from		sc_mem_m_ucf_resign_cause
where	resign_cause_code =
			(
				SELECT	resign_code
				from		sc_mem_m_resign_requestment
				where (membership_no = as_memno)
        and ( approve_result = '1' )
				and		(approve_date =
							(
							SELECT	max(tab_b.approve_date)
							from		sc_mem_m_resign_requestment tab_b
							where (sc_mem_m_resign_requestment.membership_no = tab_b.membership_no)
							and (tab_b.approve_result = '1')
              and ( sc_mem_m_resign_requestment.cancel_status <> '1' )
							)) 
		);
  return ls_cause_name;
exception
when no_data_found then return null;
when others then CALL spa_dberror('fpa_get_resign_cause_name');return null;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
